import { useQuery, useMutation, useQueryClient } from "@tanstack/react-query";
import i18n from "i18next";
import { supabase } from "@/integrations/supabase/client";
import { useAuth } from "@/contexts/AuthContext";
import { toast } from "sonner";

export interface Restaurant {
  id: string;
  name: string;
  name_en?: string;
  name_pt?: string;
  address: string;
  lat: number;
  lng: number;
  phone?: string | null;
  opening_hours?: any;
  type: string[];
  type_en?: string[];
  type_pt?: string[];
  rating?: number;
  description?: string | null;
  description_en?: string | null;
  description_pt?: string | null;
  announcement_en?: string | null;
  announcement_pt?: string | null;
  announcement_zh?: string | null;
  image_url?: string | null;
  cover_image_url?: string | null;
  website_url?: string | null;
  show_website_button?: boolean;
  visible?: boolean;
  template?: string;
  owner_avatar_url?: string | null;
  owner_bio?: string | null;
  owner_bio_en?: string | null;
  owner_bio_pt?: string | null;
  photo_story_zh?: string | null;
  photo_story_en?: string | null;
  photo_story_pt?: string | null;
  created_at: string;
}

export const useRestaurants = (searchQuery?: string, typeFilter?: string) => {
  return useQuery({
    queryKey: ["restaurants", searchQuery, typeFilter],
    queryFn: async () => {
      let query = supabase
        .from("restaurants")
        .select("id,name,name_en,name_pt,address,lat,lng,phone,opening_hours,type,type_en,type_pt,rating,image_url,cover_image_url,visible,template,photo_story_zh,photo_story_en,photo_story_pt,created_at,store_level")
        .eq("visible", true)
        .order("rating", { ascending: false });

      if (searchQuery) {
        query = query.or(`name.ilike.%${searchQuery}%,address.ilike.%${searchQuery}%`);
      }

      if (typeFilter) {
        // Split multiple types by comma and search with OR logic
        const types = typeFilter.split(',');
        const orConditions = types.flatMap(type => [
          `type.cs.{${type}}`,
          `type_en.cs.{${type}}`,
          `type_pt.cs.{${type}}`
        ]);
        query = query.or(orConditions.join(','));
      }

      const { data, error } = await query;

      if (error) throw error;
      return data as Restaurant[];
    },
  });
};

export const useRestaurant = (id: string) => {
  return useQuery({
    queryKey: ["restaurant", id],
    queryFn: async () => {
      const { data, error } = await supabase
        .from("restaurants")
        .select("*")
        .eq("id", id)
        .single();

      if (error) throw error;
      return data as Restaurant;
    },
    enabled: !!id,
  });
};

export const useFavoriteIds = () => {
  const { user } = useAuth();

  return useQuery({
    queryKey: ["favorite-ids", user?.id],
    queryFn: async () => {
      if (!user) return [];

      const { data, error } = await supabase
        .from("favorites")
        .select("restaurant_id")
        .eq("user_id", user.id);

      if (error) throw error;
      return data.map(f => f.restaurant_id);
    },
    enabled: !!user,
  });
};

// Keep the old name for backwards compatibility but make it use the new one
export const useFavorites = useFavoriteIds;

export const useToggleFavorite = () => {
  const { user } = useAuth();
  const queryClient = useQueryClient();

  return useMutation({
    mutationFn: async (restaurantId: string) => {
      if (!user) throw new Error("Must be logged in");

      // Check if already favorited
      const { data: existing } = await supabase
        .from("favorites")
        .select("id")
        .eq("user_id", user.id)
        .eq("restaurant_id", restaurantId)
        .maybeSingle();

      if (existing) {
        // Remove favorite
        const { error } = await supabase
          .from("favorites")
          .delete()
          .eq("id", existing.id);

        if (error) throw error;
        return { action: "removed" };
      } else {
        // Add favorite
        const { error } = await supabase
          .from("favorites")
          .insert({
            user_id: user.id,
            restaurant_id: restaurantId,
          });

        if (error) throw error;
        return { action: "added" };
      }
    },
    onSuccess: (result) => {
      queryClient.invalidateQueries({ queryKey: ["favorites"] });
      toast.success(i18n.t(result.action === "added" ? "toast.favoriteAdded" : "toast.favoriteRemoved"));
    },
    onError: (error: any) => {
      if (error.message === "Must be logged in") {
        toast.error(i18n.t("toast.signInToFavorite"));
      } else {
        toast.error(i18n.t("toast.favoritesUpdateFailed"));
      }
    },
  });
};

