// Reverse map: translate localized tag back to English key (for filtering)
const reverseTypeTagMap: Record<string, string> = {};
// Build reverse map from zh and pt (the DB-stored localized values)
for (const lang of ["zh", "pt"]) {
  const map = typeTagTranslations[lang];
  if (map) {
    for (const [en, localized] of Object.entries(map)) {
      reverseTypeTagMap[localized] = en;
    }
  }
}

/**
 * Translate a type tag to the display language.
 * Input can be in any DB language (zh, en, pt). Output is the current UI language.
 * Falls back to the original tag if no translation found.
 */
export function getTypeDisplayLabel(tag: string, lang: string): string {
  // If already in the target language's map values, return as-is
  const targetMap = typeTagTranslations[lang];
  if (targetMap) {
    // Check if tag is already a value in this language
    if (Object.values(targetMap).includes(tag)) return tag;
    // Try direct English key match
    if (targetMap[tag]) return targetMap[tag];
    // Try reverse lookup: tag might be zh/pt, find English key first
    const enKey = reverseTypeTagMap[tag];
    if (enKey && targetMap[enKey]) return targetMap[enKey];
  }
  return tag;
}

export const useRestaurantTypes = () => {
  return useQuery({
    queryKey: ["restaurant-types", i18n.language],
    queryFn: async () => {
      const currentLang = i18n.language;
      // Determine which field to use based on language
      const typeField = currentLang === "zh" ? "type" : 
                       currentLang === "pt" ? "type_pt" : 
                       "type_en";
      
      const { data, error } = await supabase
        .from("restaurants")
        .select(`type, type_en, type_pt`)
        .order("type");

      if (error) throw error;
      
      // Get the appropriate type field based on language
      const allTypes = data.flatMap(r => {
        const types = r[typeField as keyof typeof r];
        // Fallback to English if localized version doesn't exist
        return types || r.type_en || r.type || [];
      });
      
      const uniqueTypes = Array.from(new Set(allTypes)).sort();
      return uniqueTypes;
    },
  });
};
